if (!items.length) {
  return [{ json: { mode: "generate" } }];
}

let best = null;
let bestScore = 0;

for (const item of items) {
  const r = item.json;

  let ingredients = r.ingredients;

  if (typeof ingredients === "string") {
    try {
      ingredients = JSON.parse(ingredients);
    } catch {
      ingredients = ingredients.split(",");
    }
  }

  const ingredientCount = ingredients.length;
  const similarity = r.similarity || 0;

  // penalty nếu recipe quá ít ingredient
  const factor = ingredientCount < 4 ? 0.6 : 1;

  const score = similarity * factor;

  if (score > bestScore) {
    bestScore = score;
    best = r;
  }
}

if (!best || bestScore < 0.7) {
  return [{ json: { mode: "generate" } }];
}

return [
  {
    json: {
      mode: "found",
      id: best.id,
      title: best.title,
      ingredients: best.ingredients,
      instruction: best.instruction,
      similarity: best.similarity,
      score: bestScore
    }
  }
];

const recipe = $input.first().json;

return [{
  json: {
    mode: "found",
    recipe_id: recipe.id,
    instructions: recipe.instruction
  }
}];

