let required = $('Pick Best Recipe Match1').first().json.ingredients;
let user = $('Join Ingredients').first().json.joined_ingredients;

// convert required -> array nếu đang là string
if (typeof required === "string") {
  required = JSON.parse(required.replace(/'/g, '"'));
}

// convert user -> array
if (typeof user === "string") {
  user = user.split(",").map(i => i.trim().toLowerCase());
}

// normalize required
required = required.map(i => i.trim().toLowerCase());

const missing = required.filter(i => !user.includes(i));

return [
  {
    json: {
      ...$json,
      missing_ingredients: missing
    }
  }
];

